#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long a;
        scanf("%lld", &a);
        if (a % 3 == 0 || a % 3 == 1 || (a > 1 && a % 3 == 2)) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

