import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long a = sc.nextLong();
            if (a % 3 == 0 || a % 3 == 1 || (a > 1 && a % 3 == 2)) {
                System.out.println("yes");
            } else {
                System.out.println("no");
            }
        }
    }
}

